module morphological_dilation(
    input [8:0] eroded_image,       // 3x3 eroded_image represented as a 9-bit input
    output reg dilated_pixel // Result of dilation
);

always @(*) begin
    // Dilation: Set output to 1 if any neighbor is 1
    if (eroded_image[0] | eroded_image[1] | eroded_image[2] | 
        eroded_image[3] | eroded_image[4] | eroded_image[5] | 
        eroded_image[6] | eroded_image[7] | eroded_image[8]) 
        dilated_pixel = 1'b1;
    else 
        dilated_pixel = 1'b0;
end

endmodule
